import{_ as e,c as t,o,a4 as a}from"./chunks/framework.nQaBHiNx.js";const m=JSON.parse('{"title":"计算机是怎么跑起来的","description":"","frontmatter":{},"headers":[],"relativePath":"computer/book/how-the-computer-works/index.md","filePath":"computer/book/how-the-computer-works/index.md"}'),i={name:"computer/book/how-the-computer-works/index.md"},l=a('<h1 id="计算机是怎么跑起来的" tabindex="-1">计算机是怎么跑起来的 <a class="header-anchor" href="#计算机是怎么跑起来的" aria-label="Permalink to &quot;计算机是怎么跑起来的&quot;">​</a></h1><p>本书倡导在计算机迅速发展、技术不断革新的今天，回归到计算机的基础知识上。</p><p>通过探究计算机的本质，提升工程师对计算机的兴趣，在面对复杂的最新技术时，能够迅速掌握其要点并灵活运用。</p><p>本书以图配文，以计算机的三大原则为开端、相继介绍了计算机的结构、手工汇编、程序流程、算法、数据结构、面向对象编程、数据库、TCP/IP 网络、数据加密、XML、计算机系统开发以及 SE 的相关知识。</p><ul><li>第一章 计算机的三大原则</li><li>第二章 试着制造一台计算机</li><li>第三章 体验一次手工汇编</li><li>第四章 程序像河水一样流动着</li><li>第五章 与算法成为好朋友</li><li>第六章 与数据结构成为好朋友</li><li>第七章 使用面向对象编程</li><li>第八章 一用就会的数据库</li><li>第九章 理解 TCP/IP 网络</li><li>第十章 试着加密数据吧</li><li>第十一章 XML 究竟是什么</li><li>第十二章 SE 负责监管计算机系统的构建</li></ul><h2 id="学习资料" tabindex="-1">学习资料 <a class="header-anchor" href="#学习资料" aria-label="Permalink to &quot;学习资料&quot;">​</a></h2><p><a href="https://book.douban.com/subject/26397183/" target="_blank" rel="noreferrer">豆瓣读书 - 《计算机是怎样跑起来的》 - [日]矢泽久雄</a></p>',7),r=[l];function c(n,s,_,p,d,h){return o(),t("div",null,r)}const f=e(i,[["render",c]]);export{m as __pageData,f as default};
